{
  "learning_outcomes": [
    {
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry",
      "topic": "Conceptual Foundations and Measurement",
      "outcomes": [
        "Understand nature of matter, properties, measurement, uncertainty, laws of combination, atomic theory",
        "Apply mole concept, molar masses, percentage composition, stoichiometry calculations",
        "Represent chemical phenomena at macroscopic, molecular, and symbolic levels"
      ]
    },
    {
      "unit_name": "Structure of Atom",
      "chapter_name": "Structure of Atom",
      "topic": "Atomic Structure and Quantum Mechanics",
      "outcomes": [
        "Trace discovery of sub-atomic particles and evolution from Bohr's model to Quantum Mechanical Model"
      ]
    },
    {
      "unit_name": "Classification of Elements and Periodicity in Properties",
      "chapter_name": "Classification of Elements and Periodicity in Properties",
      "topic": "Periodic Classification and Trends",
      "outcomes": [
        "Apply modern periodic law and understand genesis of periodic classification"
      ]
    },
    {
      "unit_name": "Chemical Bonding and Molecular Structure",
      "chapter_name": "Chemical Bonding and Molecular Structure",
      "topic": "Chemical Bonding Theories",
      "outcomes": [
        "Apply Kossel-Lewis approach, VSEPR theory, Valence Bond Theory, Hybridisation, and Molecular Orbital Theory"
      ]
    },
    {
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics",
      "topic": "Thermodynamics and Spontaneity",
      "outcomes": [
        "Apply concepts of calorimetry, reaction enthalpies, spontaneity, and equilibrium via Gibbs Energy"
      ]
    },
    {
      "unit_name": "Equilibrium",
      "chapter_name": "Equilibrium",
      "topic": "Chemical Equilibrium Principles",
      "outcomes": [
        "Apply Law of Chemical Equilibrium, understand homogeneous/heterogeneous equilibria, relationship between K, Q, G"
      ]
    },
    {
      "unit_name": "Redox Reactions",
      "chapter_name": "Redox Reactions",
      "topic": "Redox and Electrode Processes",
      "outcomes": [
        "Apply classical ideas, oxidation numbers, and electrode processes"
      ]
    },
    {
      "unit_name": "Organic Chemistry: Some basic Principles and Techniques",
      "chapter_name": "Organic Chemistry: Some basic Principles and Techniques",
      "topic": "Organic Chemistry Fundamentals",
      "outcomes": [
        "Apply structural representations, nomenclature, isomerism concepts, and fundamental reaction mechanism principles"
      ]
    },
    {
      "unit_name": "Hydrocarbons",
      "chapter_name": "Hydrocarbons",
      "topic": "Hydrocarbon Classification and Properties",
      "outcomes": [
        "Classify alkanes, alkenes, alkynes, aromatic hydrocarbons"
      ]
    }
  ]
}
